## 1. CORRECTED ATOMIC HOTPATCH KERNEL

```asm
; RawrXD_Hotpatch_Kernel.asm — Shadow-Page Detour Implementation
; Requires: Target page must be VirtualProtect'd PAGE_EXECUTE_READWRITE by C++ bridge

.code
ALIGN 16

; -------------------------------------------------------------------------------
; asm_hotpatch_atomic_swap
; RCX = TargetFunc (14 bytes available for overwrite)
; RDX = NewFunc (destination)
; R8  = TrampolineBuf (optional, for original preservation)
; Returns: RAX = 0 success, -1 alignment error, -2 atomic fail
; -------------------------------------------------------------------------------
asm_hotpatch_atomic_swap PROC FRAME
    push    rbx
    .pushreg rbx
    push    rsi
    .pushreg rsi
    push    rdi
    .pushreg rdi
    .endprolog

    ; Verify 16-byte alignment for atomic operations
    test    rcx, 0Fh
    jnz     @@error_align

    ; Build 14-byte absolute jump in scratch (RAX will point to it)
    ; Format: FF 25 00 00 00 00 [64-bit addr] (JMP [RIP+0])
    sub     rsp, 16
    mov     word ptr [rsp], 025FFh      ; FF 25 (JMP indirect)
    mov     dword ptr [rsp+2], 0        ; Displacement 0
    mov     qword ptr [rsp+6], rdx      ; Absolute destination
    
    ; Atomic 8-byte write (first part of jump)
    mov     rax, qword ptr [rsp]        ; Load new 8 bytes
    mov     rbx, qword ptr [rcx]        ; Load old 8 bytes (for backup)
    lock cmpxchg qword ptr [rcx], rax   ; Atomic compare-exchange
    jne     @@error_atomic
    
    ; Atomic 6-byte write (second part—crosses 8-byte boundary, use movsq with lock)
    mov     rax, qword ptr [rsp+8]      ; Load new 6 bytes (actually 8, we mask)
    and     rax, 0FFFFFFFFFFFFh         ; Mask to 6 bytes
    mov     rbx, qword ptr [rcx+8]      
    and     rbx, 0FFFF000000000000h     ; Preserve upper 2 bytes from original
    or      rax, rbx                    ; Combine
    lock xchg qword ptr [rcx+8], rax    ; Atomic swap (not cmpxchg, we already verified)
    
    ; Memory fence to serialize instruction cache
    mfence
    clflush [rcx]                       ; Invalidate cache line
    clflush [rcx+8]
    mfence
    
    add     rsp, 16
    xor     eax, eax
    pop     rdi
    pop     rsi
    pop     rbx
    ret

@@error_align:
    mov     eax, -1
    pop     rdi
    pop     rsi
    pop     rbx
    ret

@@error_atomic:
    add     rsp, 16
    mov     eax, -2
    pop     rdi
    pop     rsi
    pop     rbx
    ret
asm_hotpatch_atomic_swap ENDP

; -------------------------------------------------------------------------------
; asm_hotpatch_install_trampoline
; Preserves original function by copying first 14 bytes to trampoline + jump back
; RCX = TargetFunc, RDX = TrampolineBuf (min 32 bytes), R8 = BufSize
; -------------------------------------------------------------------------------
asm_hotpatch_install_trampoline PROC FRAME
    push    rbx
    .pushreg rbx
    push    rsi
    .pushreg rsi
    push    rdi
    .pushreg rdi
    .endprolog

    ; Copy original 14 bytes to trampoline
    mov     rsi, rcx
    mov     rdi, rdx
    mov     rcx, 14
    rep movsb
    
    ; Append jump back to original+14
    mov     word ptr [rdi], 025FFh      ; JMP indirect
    mov     dword ptr [rdi+2], 0
    lea     rax, [rsi+14]               ; Original + 14
    mov     qword ptr [rdi+6], rax
    
    pop     rdi
    pop     rsi
    pop     rbx
    ret
asm_hotpatch_install_trampoline ENDP

END
