constexpr uint32_t PEB_NT_GLOBAL_FLAG_OFFSET = 0x068;
constexpr uint32_t NT_GLOBAL_FLAG_DEBUG = 0x70; // FLG_HEAP_ENABLE_TAIL_CHECK | FLG_HEAP_ENABLE_FREE_CHECK | FLG_HEAP_VALIDATE_PARAMETERS

// Hash context for .text section verification
struct CodeSectionHash {
    std::array<uint8_t, 32> hash;
    uint64_t timestamp;
};

class SentinelWatchdog {
public:
    static SentinelWatchdog& instance() {
        static SentinelWatchdog s;
        return s;
    }

    // Start monitoring thread
    void activate() {
        if (m_running.exchange(true)) return;
        
        // Capture baseline hash of .text section
        if (!captureBaselineHash()) {
            // If we can't hash ourselves, assume compromise
            triggerLockdown("Baseline capture failed");
            return;
        }
        
        m_watchdogThread = std::thread(&SentinelWatchdog::watchdogLoop, this);
        
        // Set thread priority to time-critical (runs even under load)
        SetThreadPriority(m_watchdogThread.native_handle(), THREAD_PRIORITY_TIME_CRITICAL);
    }

    void deactivate() {
        m_running = false;
        if (m_watchdogThread.joinable()) {
            m_watchdogThread.join();
        }
    }

    // Manual trigger (e.g., from AVL detecting algorithmic drift)
    void triggerLockdown(const std::string& reason) {
        if (m_lockdownTriggered.exchange(true)) return; // Already locked
        
        // 1. Immediate workspace encryption
        auto& crypto = Crypto::Camellia256Bridge::instance();
        if (crypto.isInitialized()) {
            // Get workspace path from IDE config
            char workspacePath[MAX_PATH];
            if (GetEnvironmentVariableA("RAWRXD_WORKSPACE", workspacePath, MAX_PATH)) {
                crypto.encryptWorkspace(workspacePath, true); // in-place
            }
        }
        
        // 2. Wipe sensitive memory
        SecureZeroMemory(&m_baselineHash, sizeof(m_baselineHash));
        
        // 3. Alert system (write to event log, not UI which may be compromised)
        HANDLE hEvent = RegisterEventSourceA(nullptr, "RawrXD-Sentinel");
        if (hEvent) {
            const char* strings[2] = { "UNAUTHORIZED_MODIFICATION_DETECTED", reason.c_str() };
            ReportEventA(hEvent, EVENTLOG_ERROR_TYPE, 0, 0xC0000001, nullptr, 2, 0, strings, nullptr);
            DeregisterEventSource(hEvent);
        }
        
        // 4. Terminate debuggers (optional aggressive defense)
        // enumerateProcessesAndKillDebuggers();
        
        // 5. Exit process gracefully but fast
        ExitProcess(0xC0000605); // STATUS_INVALID_IMAGE_HASH custom
    }

private:
    SentinelWatchdog() = default;
    ~SentinelWatchdog() { deactivate(); }

    std::atomic<bool> m_running{false};
    std::atomic<bool> m_lockdownTriggered{false};
    std::thread m_watchdogThread;
    CodeSectionHash m_baselineHash{};
    uint64_t m_textBase = 0;
    uint64_t m_textSize = 0;

    bool captureBaselineHash() {
        // Get module handle (our own EXE)
        HMODULE hMod = GetModuleHandleA(nullptr);
        if (!hMod) return false;
        
        // Parse PE headers to find .text section
        auto* dosHeader = (PIMAGE_DOS_HEADER)hMod;
        auto* ntHeaders = (PIMAGE_NT_HEADERS)((uint8_t*)hMod + dosHeader->e_lfanew);
        
        PIMAGE_SECTION_HEADER section = IMAGE_FIRST_SECTION(ntHeaders);
        for (int i = 0; i < ntHeaders->FileHeader.NumberOfSections; i++, section++) {
            if (memcmp(section->Name, ".text\0", 5) == 0) {
                m_textBase = (uint64_t)hMod + section->VirtualAddress;
                m_textSize = section->Misc.VirtualSize;
                break;
            }
        }
        
        if (m_textSize == 0) return false;
        
        // Compute SHA-256 of .text section
        BCRYPT_ALG_HANDLE hAlg = nullptr;
        BCRYPT_HASH_HANDLE hHash = nullptr;
        if (!BCRYPT_SUCCESS(BCryptOpenAlgorithmProvider(&hAlg, BCRYPT_SHA256_ALGORITHM, nullptr, 0))) {
            return false;
        }
        
        if (!BCRYPT_SUCCESS(BCryptCreateHash(hAlg, &hHash, nullptr, 0, nullptr, 0, 0))) {
            BCryptCloseAlgorithmProvider(hAlg, 0);
            return false;
        }
        
        // Hash in 64KB chunks to avoid large allocations
        constexpr size_t CHUNK = 65536;
        uint8_t buffer[CHUNK];
        size_t remaining = m_textSize;
        uint8_t* ptr = (uint8_t*)m_textBase;
        
        while (remaining > 0) {
            size_t toHash = (remaining > CHUNK) ? CHUNK : remaining;
            BCryptHashData(hHash, ptr, (ULONG)toHash, 0);
            ptr += toHash;
            remaining -= toHash;
        }
        
        DWORD hashLen = 32;
        BCryptFinishHash(hHash, m_baselineHash.hash.data(), hashLen, 0);
        m_baselineHash.timestamp = GetTickCount64();
        
        BCryptDestroyHash(hHash);
        BCryptCloseAlgorithmProvider(hAlg, 0);
        
        return true;
    }

    bool verifyCodeIntegrity() {
        BCRYPT_ALG_HANDLE hAlg = nullptr;
        BCRYPT_HASH_HANDLE hHash = nullptr;
        std::array<uint8_t, 32> currentHash{};
        
        if (!BCRYPT_SUCCESS(BCryptOpenAlgorithmProvider(&hAlg, BCRYPT_SHA256_ALGORITHM, nullptr, 0))) {
            return false; // Fail closed
        }
        
        BCryptCreateHash(hAlg, &hHash, nullptr, 0, nullptr, 0, 0);
        
        // Quick hash of .text
        BCryptHashData(hHash, (uint8_t*)m_textBase, (ULONG)m_textSize, 0);
        DWORD hashLen = 32;
        BCryptFinishHash(hHash, currentHash.data(), hashLen, 0);
        
        BCryptDestroyHash(hHash);
        BCryptCloseAlgorithmProvider(hAlg, 0);
        
        // Constant-time comparison to prevent timing leaks
        volatile uint8_t diff = 0;
        for (int i = 0; i < 32; i++) {
            diff |= currentHash[i] ^ m_baselineHash.hash[i];
        }
        
        return diff == 0;
    }

    bool detectDebugger() {
        // Check 1: PEB.BeingDebugged (trivial, but catches naive debuggers)
        auto* peb = (uint8_t*)__readgsqword(0x60); // TEB->PEB
        if (peb[PEB_BEING_DEBUGGED_OFFSET]) return true;
        
        // Check 2: PEB.NtGlobalFlag (heap checks enabled)
        uint32_t ntGlobal = *(uint32_t*)(peb + PEB_NT_GLOBAL_FLAG_OFFSET);
        if ((ntGlobal & NT_GLOBAL_FLAG_DEBUG) == NT_GLOBAL_FLAG_DEBUG) return true;
        
        // Check 3: Hardware breakpoint registers (DR0-DR3)
        CONTEXT ctx = {};
        ctx.ContextFlags = CONTEXT_DEBUG_REGISTERS;
        if (GetThreadContext(GetCurrentThread(), &ctx)) {
            if (ctx.Dr0 || ctx.Dr1 || ctx.Dr2 || ctx.Dr3) return true;
        }
        
        // Check 4: Timing analysis (rdtsc delta > threshold indicates breakpoint)
        uint64_t t1 = __rdtsc();
        __nop(); __nop(); __nop();
        uint64_t t2 = __rdtsc();
        if ((t2 - t1) > 1000) return true; // Adjust threshold based on CPU
        
        return false;
    }

    void watchdogLoop() {
        // Check interval: 500ms (fast enough to catch tampering, slow enough for CPU)
        constexpr DWORD CHECK_INTERVAL_MS = 500;
        
        while (m_running) {
            // Priority 1: Debugger detection
            if (detectDebugger()) {
                triggerLockdown("External debugger detected");
                return;
            }
            
            // Priority 2: Code integrity verification
            if (!verifyCodeIntegrity()) {
                triggerLockdown(".text section hash mismatch (hotpatch tampering)");
                return;
            }
            
            // Priority 3: AVL heartbeat (if AVL stops responding, assume deadlock/compromise)
            // This requires AVL to increment a shared atomic counter
            // static std::atomic<uint64_t> avlHeartbeat;
            // if (GetTickCount64() - lastAvlBeat > 5000) triggerLockdown("AVL deadlock");
            
            Sleep(CHECK_INTERVAL_MS);
        }
    }
};

